"""Small localhost-only Laplace UI with revision-aware streaming."""

from __future__ import annotations

import html

from fastapi.responses import HTMLResponse


def _document(title: str, body: str) -> HTMLResponse:
    return HTMLResponse(
        "<!doctype html><html lang='en'><head><meta charset='utf-8'>"
        "<meta name='viewport' content='width=device-width,initial-scale=1'>"
        f"<title>{html.escape(title)}</title><style>{_css()}</style></head>"
        f"<body>{body}<script>{_js()}</script></body></html>"
    )


def project_page(title: str, project_name: str, route: str = "/chat") -> HTMLResponse:
    name = html.escape(project_name)
    body = f"""
    <div class="app" data-page="{html.escape(route)}">
      <aside class="sidebar"><div class="brand"><b class="mark">L</b><div><strong>Laplace</strong><small>Local research assistant</small></div></div>
      <div class="eyebrow">PROJECT</div><strong>{name}</strong><button id="new-chat" class="primary">＋ New chat</button>
      <input id="conversation-filter" placeholder="Search conversations"><div id="conversation-list"></div>
      <div class="eyebrow">COLLECTIONS</div><div id="collections"></div><label>Mode <select id="mode"><option>ASK</option><option>SEARCH</option><option>WRITE</option><option>RESEARCH</option></select></label>
      <nav><a href="/chat">Chat</a><a href="/library">Library</a><a href="/research">Research</a><a href="/downloads">Downloads</a><a href="/settings">Settings</a><a href="/dashboard">System status</a></nav><small class="privacy">● Localhost only · qwen3:4b</small></aside>
      <main><header><div class="eyebrow">{html.escape(title.upper())}</div><h1 id="conversation-title">New chat</h1><span class="badge">Grounded local mode</span></header>
      <section id="messages" aria-live="polite"><div class="empty"><b class="empty-mark">L</b><h2>Evidence-grounded research assistant</h2><p>Ask about indexed documents and inspect exact page evidence.</p></div></section>
      <section id="secondary-page" class="hidden"></section><div id="status-line"></div>
      <form id="composer"><textarea id="prompt" rows="2" placeholder="Ask a grounded question…"></textarea><div><button type="button" id="stop" class="secondary hidden">Stop</button><label class="attach">＋<input id="attachment" type="file" accept=".pdf,.txt,.md,.csv,.json" hidden></label><button class="send">Send ↗</button></div></form></main>
      <aside id="evidence-panel"><h3>Evidence <button id="close-evidence">×</button></h3><div id="evidence-content"><p class="muted">Select a citation to inspect its retrieved passage.</p></div></aside>
    </div>"""
    return _document(f"Laplace · {title}", body)


def offline_dashboard(project_name: str = "") -> HTMLResponse:
    name = html.escape(project_name or "Current project")
    body = f"""<div class="dashboard"><h1>Laplace system status</h1><p>Project: <strong>{name}</strong></p><div class="status-grid"><div>Service<strong>127.0.0.1</strong></div><div>Model<strong>qwen3:4b</strong></div><div>Embeddings<strong>qwen3-embedding:0.6b</strong></div><div>Evidence<strong id="doc-count">Loading…</strong></div></div><pre id="status-json">Loading project status…</pre><a href="/chat">Open chat →</a></div><script>fetch('/api/project/status').then(r=>r.json()).then(v=>{{document.getElementById('doc-count').textContent=v.documents??0;document.getElementById('status-json').textContent=JSON.stringify(v,null,2)}})</script>"""
    return _document("Laplace · System status", body)


def _css() -> str:
    return """*{box-sizing:border-box}body{margin:0;background:#f7f8fb;color:#172033;font:14px/1.5 system-ui,sans-serif}.app{min-height:100vh;display:grid;grid-template-columns:245px 1fr 310px}.sidebar{background:#fff;border-right:1px solid #e2e6ee;padding:20px;display:flex;flex-direction:column;gap:12px}.brand{display:flex;gap:9px;align-items:center;font-size:18px}.brand small{display:block;color:#718096;font-size:11px;font-weight:400}.mark,.empty-mark{display:grid;place-items:center;background:#315efb;color:#fff;border-radius:10px;width:34px;height:34px}.eyebrow{font-size:10px;letter-spacing:.12em;color:#98a2b3;font-weight:700}.primary,.send{border:0;background:#315efb;color:#fff;border-radius:8px;padding:9px 12px;font-weight:700;cursor:pointer}input,textarea,select{border:1px solid #e2e6ee;border-radius:8px;padding:9px;font:inherit;background:#fff}input{width:100%}nav{border-top:1px solid #e2e6ee;padding-top:10px;display:grid;gap:3px}nav a{padding:6px;color:#526078;text-decoration:none}nav a:hover{color:#315efb;background:#edf1ff}.privacy{margin-top:auto;color:#138a65}main{min-width:0;display:flex;flex-direction:column;min-height:100vh}header{height:76px;background:#fff;border-bottom:1px solid #e2e6ee;padding:16px 7%;position:relative}header h1{font-size:18px;margin:1px 0}.badge{position:absolute;right:7%;top:29px;color:#138a65;font-size:11px}#messages{flex:1;overflow:auto;padding:34px 8%}.empty{text-align:center;color:#718096;margin:14vh auto}.empty h2{color:#172033}.message{display:flex;gap:10px;max-width:840px;margin:0 0 20px}.message.user{margin-left:auto;justify-content:flex-end}.avatar{width:27px;height:27px;border-radius:8px;background:#e9edff;color:#315efb;padding:5px;font-weight:700}.bubble{background:#fff;border:1px solid #e2e6ee;border-radius:11px;padding:12px 15px;box-shadow:0 8px 25px #23305012}.message.user .bubble{background:#315efb;color:#fff;border:0}.citation{color:#315efb;background:#edf1ff;border:0;border-radius:4px;padding:1px 4px;cursor:pointer}.rejected-draft{opacity:.78}.rejected{border-left:3px solid #d28c2d;padding-left:8px}.rejected summary{color:#9a5b08;font-size:12px;cursor:pointer}.fallback{color:#138a65;font-size:11px;margin-top:8px}.hidden{display:none}#status-line{min-height:25px;color:#718096;padding:0 8% 8px;font-size:12px}#composer{background:#fff;border-top:1px solid #e2e6ee;padding:13px 8%;display:flex;gap:8px;align-items:flex-end}#composer textarea{flex:1;resize:none}.secondary{border:1px solid #e2e6ee;background:#fff;color:#b34c4c;border-radius:8px;padding:8px;cursor:pointer}#evidence-panel{background:#fff;border-left:1px solid #e2e6ee;padding:20px;overflow:auto}#evidence-panel h3{margin:0}#evidence-panel h3 button{float:right;border:0;background:none;font-size:18px}.evidence-card{border-top:1px solid #e2e6ee;margin-top:14px;padding-top:12px}.quote{border-left:3px solid #a8b8ff;padding-left:9px;color:#526078}.muted{color:#718096}.dashboard{max-width:1000px;margin:auto;padding:40px}.status-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.status-grid div{background:#fff;border:1px solid #e2e6ee;border-radius:10px;padding:15px;color:#718096}.status-grid strong{display:block;color:#172033;font-size:18px;margin-top:5px}.dashboard pre{background:#172033;color:#dbe5ff;border-radius:10px;padding:16px;overflow:auto}@media(max-width:1000px){.app{grid-template-columns:220px 1fr}#evidence-panel{display:none}}@media(max-width:650px){.app{display:block}.sidebar{border:0;border-bottom:1px solid #e2e6ee}.sidebar div:nth-of-type(n+3),.sidebar nav,.privacy{display:none}#messages,#composer{padding-left:15px;padding-right:15px}.status-grid{grid-template-columns:1fr 1fr}}"""


def _js() -> str:
    return r"""(()=>{const $=s=>document.querySelector(s),state={conversation:null};const activeGenerations={};const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const md=s=>'<p>'+esc(s).replace(/\n\n/g,'</p><p>').replace(/\n/g,'<br>')+'</p>';const status=m=>$('#status-line').textContent=m||'';async function api(u,o){const r=await fetch(u,{headers:{'Content-Type':'application/json',...(o?.headers||{})},...o});if(!r.ok)throw Error(await r.text());return r.json()}
function addMessage(role,content,citations=[],meta={}){const w=document.createElement('div'),rejected=meta.state==='CITATION_REJECTED'||meta.rejected;w.className='message '+role+(rejected?' rejected-draft':'');let h=md(content);(citations||[]).forEach(c=>{const n=c.citation_id,e=c.evidence_id||('E'+n);h=h.replace(new RegExp('\\[(?:'+n+'|'+e+')\\]','g'),'<button class="citation" data-citation="'+n+'">['+e+']</button>')});const prefix=rejected?'<details class="rejected"><summary>Unverified model draft · citation validation failed</summary>':'';w.innerHTML='<div class="avatar">'+(role==='user'?'You':'L')+'</div><div><div class="bubble">'+prefix+h+(rejected?'</details>':'')+(meta.fallback_used?'<div class="fallback">Grounded fallback · validated against retrieved evidence</div>':'')+'</div></div>';$('#messages').append(w);w.querySelectorAll('.citation').forEach(b=>b.onclick=()=>showEvidence(citations[Number(b.dataset.citation)-1]));$('#messages').scrollTop=$('#messages').scrollHeight;return w}
function showEvidence(c){if(!c)return;$('#evidence-content').innerHTML='<div class="evidence-card"><h3>['+esc(c.evidence_id||('E'+c.citation_id))+'] '+esc(c.title||c.filename)+'</h3><p><b>File:</b> '+esc(c.filename)+' · <b>Page:</b> '+esc(c.page??'—')+'</p><p><b>Chunk:</b> <code>'+esc(c.chunk_id)+'</code></p><p><b>Section:</b> '+esc(c.section||'—')+'</p><p class="quote">'+esc(c.quoted_evidence)+'</p></div>'}
async function loadConversations(){const v=await api('/api/chat/conversations');const l=$('#conversation-list');l.innerHTML='';(v.conversations||[]).forEach(c=>{const e=document.createElement('button');e.textContent=c.title;e.onclick=()=>openConversation(c.conversation_id);e.style='display:block;width:100%;text-align:left;border:0;background:none;padding:7px;cursor:pointer';l.append(e)})}async function loadCollections(){const v=await api('/api/project/collections');$('#collections').innerHTML=(v.collections||[]).map(c=>'<label><input type="checkbox" value="'+esc(c.name)+'" '+(c.selected?'checked':'')+'> '+esc(c.name)+' ('+esc(c.documents)+')</label>').join('<br>')}function selected(){return Array.from(document.querySelectorAll('#collections input:checked')).map(x=>x.value)}async function newConversation(){state.conversation=await api('/api/chat/conversations',{method:'POST',body:JSON.stringify({title:'New chat',collections:selected().length?selected():['MyWorks'],mode:$('#mode').value})});$('#messages').innerHTML='';$('#conversation-title').textContent='New chat';loadConversations()}async function openConversation(id){const v=await api('/api/chat/conversations/'+id);state.conversation=v;$('#conversation-title').textContent=v.title;$('#messages').innerHTML='';(v.messages||[]).forEach(m=>addMessage(m.role,m.content,m.citations,{...m,rejected:m.state==='CITATION_REJECTED'}));loadConversations()}async function ensure(){if(!state.conversation)await newConversation()}
async function send(){const q=$('#prompt').value.trim();if(!q)return;await ensure();$('#prompt').value='';addMessage('user',q);$('#stop').classList.remove('hidden');status('Searching local collections…');let candidate=null,fallback=null,ct='',ft='',latest=0;try{const r=await fetch('/api/chat/conversations/'+state.conversation.conversation_id+'/messages?stream=true',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({content:q,mode:$('#mode').value,collections:selected().length?selected():['MyWorks']})});if(!r.ok)throw Error(await r.text());const rd=r.body.getReader(),d=new TextDecoder();let buf='';while(true){const x=await rd.read();if(x.done)break;buf+=d.decode(x.value,{stream:true});const ps=buf.split('\n\n');buf=ps.pop();for(const p of ps){if(!p.startsWith('data:'))continue;const e=JSON.parse(p.slice(5));const seq=Number(e.sequence||1);if(seq<latest)continue;if(e.type==='message_started'){latest=seq;activeGenerations[e.message_id]={revision_id:e.revision_id,sequence:seq};candidate=addMessage('assistant','',[],{state:'GENERATING'})}if(e.type==='retrieval_result')status('Retrieved '+e.count+' passages…');if(e.type==='status')status(e.message);if(e.type==='token'&&candidate&&e.revision_id===activeGenerations[e.message_id]?.revision_id){ct+=e.text;candidate.querySelector('.bubble').innerHTML=md(ct)}if(e.type==='message_rejected'){candidate?.remove();candidate=addMessage('assistant',e.message.content,e.message.citations,{...e.message,rejected:true});status('Citation validation failed · preserving rejected draft')}if(e.type==='fallback_started')fallback=addMessage('assistant','',[],{fallback_used:true,state:'GROUNDED_FALLBACK'});if(e.type==='fallback_token'&&fallback){ft+=e.text;fallback.querySelector('.bubble').innerHTML=md(ft)+'<div class="fallback">Grounded fallback · validating evidence</div>'}if(e.type==='fallback_completed'&&fallback){fallback.remove();addMessage('assistant',e.message.content,e.message.citations,{...e.message,fallback_used:true});status(e.message.status+' · '+e.message.citations.length+' citations')}if(e.type==='message_completed'){candidate?.remove();addMessage('assistant',e.message.content,e.message.citations,e.message);status(e.message.status+' · '+e.message.citations.length+' citations')}if(e.type==='message_failed')throw Error(e.error)}}}catch(e){status('Error: '+e.message)}finally{$('#stop').classList.add('hidden');loadConversations()}}async function setupPage(){const page=$('.app').dataset.page;if(page==='/chat')return;$('#messages').innerHTML='<div class="secondary-card"><h2>'+page.slice(1)+'</h2><p class="muted">Project-local workspace view.</p><div id="page-data">Loading…</div></div>';$('#composer').classList.add('hidden');$('#evidence-panel').classList.add('hidden');if(page==='/library'){const v=await api('/api/project/collections');$('#page-data').innerHTML=(v.collections||[]).map(c=>'<p><b>'+esc(c.name)+'</b> · '+esc(c.documents)+' documents</p>').join('')}else if(page==='/downloads'){const v=await api('/api/project/status');$('#page-data').textContent='Indexed documents: '+(v.documents??0)+' · Downloads: '+(v.downloads??0)}else if(page==='/settings'){const v=await api('/api/project/settings');$('#page-data').textContent=Object.keys(v.settings||{}).join(', ')+' (edit with laplace --edit)'}else if(page==='/research'){$('#page-data').textContent='Use /api/search/scholarly for configured local metadata workflow.'}}$('#new-chat').onclick=newConversation;$('#composer').onsubmit=e=>{e.preventDefault();send()};$('#stop').onclick=async()=>{if(state.conversation)await api('/api/chat/conversations/'+state.conversation.conversation_id+'/stop',{method:'POST'});status('Stop requested…')};$('#close-evidence').onclick=()=>$('#evidence-content').innerHTML='<p class="muted">Select a citation to inspect its retrieved passage.</p>';setupPage().catch(e=>status(e.message));loadConversations().catch(e=>status(e.message));loadCollections().catch(e=>status(e.message));})();"""
